using System;
using System.Collections.Generic;
using UnityEngine;

[DisallowMultipleComponent]
public sealed class ProgressionService : MonoBehaviour
{
    public static ProgressionService Instance
    {
        get;
        private set;
    }

    public static event Action<BallDefinition> BallUnlocked;

    public static event Action<BoardComponentDefinition>
        ComponentUnlocked;

    [Header("Debug")]
    public bool everythingUnlocked = false;

    [Header("Config")]
    [Tooltip(
        "Assign the ProgressionConfig asset. "
        + "If left null the service will attempt to load "
        + "one from Resources at runtime.")]
    [SerializeField] private ProgressionConfig config;

    private const string resourceFallbackPath =
        "ProgressionConfig";

    [RuntimeInitializeOnLoadMethod(
        RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void Bootstrap()
    {
        if (Instance != null)
        {
            return;
        }

        var go = new GameObject(nameof(ProgressionService));
        DontDestroyOnLoad(go);
        go.AddComponent<ProgressionService>();
    }

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            Destroy(gameObject);
            return;
        }

        Instance = this;
        DontDestroyOnLoad(gameObject);

        EnsureConfig();
    }

    private void OnEnable()
    {
        ProfileService.ActiveSlotChanged +=
            OnActiveSlotChanged;
    }

    private void OnDisable()
    {
        ProfileService.ActiveSlotChanged -=
            OnActiveSlotChanged;
    }

    public ProgressionConfig Config
    {
        get
        {
            EnsureConfig();
            return config;
        }
    }

    public void CheckAndGrantUnlocks()
    {
        if (config == null)
        {
            return;
        }

        ProfileSaveData profile =
            ProfileService.GetActiveProfileCopy();

        if (profile == null || profile.stats == null)
        {
            return;
        }

        double xp = profile.stats.totalPointsScored;
        var tiers = config.Tiers;

        for (int i = 0; i < tiers.Count; i++)
        {
            var tier = tiers[i];

            if (tier == null)
            {
                continue;
            }

            if (xp < tier.XpThreshold)
            {
                continue;
            }

            if (tier.HasValidBallReward)
            {
                string ballId = tier.RewardBallId;

                if (!string.IsNullOrEmpty(ballId))
                {
                    bool added =
                        ProfileService.AddUnlockedBall(
                            ballId);

                    if (added)
                    {
                        BallUnlocked?.Invoke(
                            tier.RewardBall);
                    }
                }
            }
            else if (tier.HasValidComponentReward)
            {
                string compId = tier.RewardComponentId;

                if (!string.IsNullOrEmpty(compId))
                {
                    bool added =
                        ProfileService
                            .AddUnlockedComponent(compId);

                    if (added)
                    {
                        ComponentUnlocked?.Invoke(
                            tier.RewardComponent);
                    }
                }
            }
        }
    }

    public bool IsBallUnlocked(string ballId)
    {
        if (everythingUnlocked) return true;
        if (string.IsNullOrEmpty(ballId))
        {
            return false;
        }

        if (config != null
            && config.IsStarterBall(ballId))
        {
            return true;
        }

        List<string> unlocked =
            ProfileService.GetUnlockedBallIds();

        return unlocked.Contains(ballId);
    }

    public bool IsComponentUnlocked(string componentId)
    {
        if (everythingUnlocked) return true;
        if (string.IsNullOrEmpty(componentId))
        {
            return false;
        }

        if (config != null
            && config.IsStarterComponent(componentId))
        {
            return true;
        }

        List<string> unlocked =
            ProfileService.GetUnlockedComponentIds();

        return unlocked.Contains(componentId);
    }

    public List<BallDefinition> GetUnlockedBallDefinitions(
        IList<BallDefinition> fullCatalog)
    {
        if (fullCatalog == null
            || fullCatalog.Count == 0)
        {
            return new List<BallDefinition>();
        }

        var result =
            new List<BallDefinition>(fullCatalog.Count);

        for (int i = 0; i < fullCatalog.Count; i++)
        {
            BallDefinition def = fullCatalog[i];

            if (def == null)
            {
                continue;
            }

            if (IsBallUnlocked(def.Id))
            {
                result.Add(def);
            }
        }

        return result;
    }

    public List<BoardComponentDefinition>
        GetUnlockedComponentDefinitions(
            IList<BoardComponentDefinition> fullCatalog)
    {
        if (fullCatalog == null
            || fullCatalog.Count == 0)
        {
            return new List<BoardComponentDefinition>();
        }

        var result =
            new List<BoardComponentDefinition>(
                fullCatalog.Count);

        for (int i = 0; i < fullCatalog.Count; i++)
        {
            BoardComponentDefinition def = fullCatalog[i];

            if (def == null)
            {
                continue;
            }

            if (IsComponentUnlocked(def.Id))
            {
                result.Add(def);
            }
        }

        return result;
    }

    public double GetCurrentXp()
    {
        ProfileSaveData profile =
            ProfileService.GetActiveProfileCopy();

        if (profile?.stats == null)
        {
            return 0d;
        }

        return profile.stats.totalPointsScored;
    }

    public ProgressionTier GetNextLockedTier()
    {
        if (config == null)
        {
            return null;
        }

        double xp = GetCurrentXp();
        var tiers = config.Tiers;

        for (int i = 0; i < tiers.Count; i++)
        {
            if (tiers[i] == null)
            {
                continue;
            }

            if (xp < tiers[i].XpThreshold)
            {
                return tiers[i];
            }
        }

        return null;
    }

    private void OnActiveSlotChanged(ProfileSlotId slot)
    {
        CheckAndGrantUnlocks();
    }

    private void EnsureConfig()
    {
        if (config != null)
        {
            return;
        }

        config = Resources.Load<ProgressionConfig>(
            resourceFallbackPath);

        if (config == null)
        {
            Debug.LogWarning(
                $"{nameof(ProgressionService)}: No "
                + "ProgressionConfig assigned or found "
                + "in Resources. Progression will be "
                + "disabled.",
                this);
        }
    }
}
